import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def waiting_penalty(arrive_time, window):
        if arrive_time < window[0]:
            return window[0] - arrive_time
        return 0

    costs = []
    for i, customer_pos in enumerate(unvisited_customers):
        tt = travel_time(cur_truck_pos, customer_pos)
        arrival = current_time + tt
        wait_pen = waiting_penalty(arrival, time_windows[i])
        total_time = tt + wait_pen
        costs.append(total_time)

    # Cooperative weight calculation
    cooperative_weights = []
    for i in range(len(unvisited_customers)):
        other_trucks_future_costs = 0
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                other_trucks_future_costs += travel_time(truck_pos, unvisited_customers[i])
        cooperative_weights.append(costs[i] / (other_trucks_future_costs + 1))  # smoothing by adding 1 to avoid division by zero

    # Select best node based on smallest cooperative weight
    best_node = np.argmin(cooperative_weights)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def time_until_end(window, current_time):
        return window[1] - current_time

    def relative_isolation(customer_pos, all_truck_positions):
        return np.mean(np.linalg.norm(all_truck_positions - customer_pos, axis=1))

    best_node = None
    max_score = -np.inf

    for i, customer_pos in enumerate(unvisited_customers):
        distance = travel_time(cur_truck_pos, customer_pos)
        isolation_score = relative_isolation(customer_pos, all_truck_pos)
        time_left = time_until_end(time_windows[i], current_time)

        # Calculate urgency based on remaining time and isolation
        urgency = 1 / (time_left + 0.1) * isolation_score

        score = urgency / (distance + 0.1)  # Adjust weighting on distance vs. urgency

        if score > max_score:
            max_score = score
            best_node = i

    return best_node

