import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    best_node = None
    highest_score = -np.inf

    for i, customer_pos in enumerate(unvisited_customers):
        time_to_customer = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + time_to_customer
        time_window_start, time_window_end = time_windows[i]

        if arrival_time > time_window_end:
            continue  # Skip if we cannot meet the time window

        # Calculate score based on remaining time and distance
        remaining_time = max(time_window_start - arrival_time, 0) + (time_window_end - arrival_time)
        score = 1 / (remaining_time + 1) + 1 / (time_to_customer + 1)  # Adding 1 to avoid division by zero

        # If customer can be reached within time window, prefer closer and urgent customers
        if score > highest_score:
            highest_score = score
            best_node = i

    if best_node is None and len(unvisited_customers) > 0:
        # If no timely reachable customer, recommend waiting (or could implement a fallback strategy)
        return None

    return best_node
